DROP TABLE IF EXISTS `order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `order` (
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `order_id` varchar(25) COLLATE utf8mb4_unicode_ci NOT NULL,
  `quantity` int unsigned NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `paid_at` datetime(6) DEFAULT NULL,
  `completed_at` datetime(6) DEFAULT NULL,
  `buyer_id` varchar(13) COLLATE utf8mb4_unicode_ci NOT NULL,
  `listing_id` varchar(25) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `product_id` varchar(13) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `seller_id` varchar(13) COLLATE utf8mb4_unicode_ci NOT NULL,
  `receiver_name` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `receiver_phone` varchar(11) COLLATE utf8mb4_unicode_ci NOT NULL,
  `shipping_address_id` bigint DEFAULT NULL,
  `shipping_address_text` varchar(300) COLLATE utf8mb4_unicode_ci NOT NULL,
  `team_id` varchar(25) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`order_id`),
  KEY `order_buyer_id_d70e4ec3_fk_user_user_id` (`buyer_id`),
  KEY `order_listing_id_bff5ffe0_fk_listing_listing_id` (`listing_id`),
  KEY `order_product_id_5feb8b6f_fk_product_product_id` (`product_id`),
  KEY `order_seller_id_48ec66ac_fk_user_user_id` (`seller_id`),
  KEY `order_shipping_address_id_fcffab25_fk_user_address_id` (`shipping_address_id`),
  KEY `order_team_id_94759d6f_fk_team_project_team_id` (`team_id`),
  CONSTRAINT `order_buyer_id_d70e4ec3_fk_user_user_id` FOREIGN KEY (`buyer_id`) REFERENCES `user` (`user_id`),
  CONSTRAINT `order_listing_id_bff5ffe0_fk_listing_listing_id` FOREIGN KEY (`listing_id`) REFERENCES `listing` (`listing_id`),
  CONSTRAINT `order_product_id_5feb8b6f_fk_product_product_id` FOREIGN KEY (`product_id`) REFERENCES `product` (`product_id`),
  CONSTRAINT `order_seller_id_48ec66ac_fk_user_user_id` FOREIGN KEY (`seller_id`) REFERENCES `user` (`user_id`),
  CONSTRAINT `order_shipping_address_id_fcffab25_fk_user_address_id` FOREIGN KEY (`shipping_address_id`) REFERENCES `user_address` (`id`),
  CONSTRAINT `order_team_id_94759d6f_fk_team_project_team_id` FOREIGN KEY (`team_id`) REFERENCES `team_project` (`team_id`),
  CONSTRAINT `order_chk_1` CHECK ((`quantity` >= 0))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
